class Solution {
public:
    long long smallestNumber(long long num) {
        if (num < 0) {
            string str = to_string(-num);
            sort(str.begin(), str.end(), greater<char>());
            for (int i = 0; i < str.size(); i++) {
                if (str[i] != '0') {
                    swap(str[0], str[i]);
                    break;
                }
            }
            return -stoll(str);
        } else {
            string str = to_string(num);
            sort(str.begin(), str.end());
            if (str[0] == '0') {
                for (int i = 1; i < str.size(); i++) {
                    if (str[i] != '0') {
                        swap(str[0], str[i]);
                        break;
                    }
                }
            }
            return stoll(str);
        }
    }
};
